import { encodeHolographicData, inflateHolographicData } from './holographic-compressor';
import { encodeCsvHologram, inflateCsvHologram } from './data-hologram';
import { AmplituhedronKnot } from '../lib';

/**
 * Integration Test & Benchmark: Holographic Compression & Data Holograms
 */

// ... (existing code)

function generateRealDNA(length: number): Uint8Array {
  const data = new Uint8Array(length);
  for (let i = 0; i < length; i++) {
    data[i] = Math.floor(Math.random() * 4); 
  }
  return data;
}

function generateAlgorithmicStructure(length: number): Uint8Array {
  const data = new Uint8Array(length);
  let state = 42; 
  for (let i = 0; i < length; i++) {
    state = (state * 1664525 + 1013904223) % 4294967296;
    data[i] = state & 0xFF;
  }
  return data;
}

function generateMassiveCSV(rows: number, cols: number): string {
  const lines: string[] = [];
  const headers = Array.from({length: cols}, (_, i) => `col_${i}`);
  lines.push(headers.join(','));
  for (let r = 0; r < rows; r++) {
    const cells = Array.from({length: cols}, (_, c) => `val_${r}_${c}`);
    lines.push(cells.join(','));
  }
  return lines.join('\n');
}

function runBenchmark() {
  console.log("=========================================");
  console.log(" HOLOGRAPHIC COMPRESSOR BENCHMARK ");
  console.log("=========================================\n");

  const PAYLOAD_SIZE = 100_000; 

  console.log("--- TEST 1: REAL EMPIRICAL DNA (HIGH ENTROPY) ---");
  const realData = generateRealDNA(PAYLOAD_SIZE);
  evaluateCompression(realData, PAYLOAD_SIZE);

  console.log("--- TEST 2: DETERMINISTIC STRUCTURE (LOW ENTROPY) ---");
  const structData = generateAlgorithmicStructure(PAYLOAD_SIZE);
  evaluateCompression(structData, PAYLOAD_SIZE);

  console.log("--- TEST 3: DATA HOLOGRAM (1,000,000 cell CSV MATRIX) ---");
  evaluateDataHologram();
}

function evaluateCompression(originalData: Uint8Array, PAYLOAD_SIZE: number) {
  // ... existing logging ...
  console.log(`[+] Original Data Size: ${PAYLOAD_SIZE.toLocaleString()} bytes`);
  const startTime = performance.now();
  const geometry = encodeHolographicData(originalData);
  const knotBytes = AmplituhedronKnot.toBytes(geometry);
  const compressTime = performance.now() - startTime;
  
  console.log(`[+] Encoded to .knot Tensor: ${knotBytes.length} bytes`);
  console.log(`[+] Compression Ratio: ${((PAYLOAD_SIZE / knotBytes.length)).toLocaleString()}x`);
  console.log(`[+] Geometry Volume: ${geometry.staticVolume}`);
  console.log(`[+] Time to encode: ${compressTime.toFixed(2)}ms\n`);

  const inflateStart = performance.now();
  const hydratedData = inflateHolographicData(geometry, PAYLOAD_SIZE);
  const inflateTime = performance.now() - inflateStart;

  let matches = 0;
  for (let i = 0; i < PAYLOAD_SIZE; i++) {
    if (originalData[i] === hydratedData[i]) matches++;
  }

  const accuracy = (matches / PAYLOAD_SIZE) * 100;
  console.log(`[RESULT] Reconstruction Accuracy: ${accuracy.toFixed(2)}%`);
  if (accuracy === 100) {
    console.log("[RESULT] Lossless Algorithmic Reconstruction: SUCCESS\n");
  } else {
    console.log("[RESULT] FAILURE: Information Loss Detected.\n");
  }
}

function evaluateDataHologram() {
  const ROWS = 10_000;
  const COLS = 100;
  const originalCsv = generateMassiveCSV(ROWS, COLS);
  const headers = originalCsv.split('\n')[0]!.split(',');
  
  console.log(`[+] Original CSV Matrix: ${ROWS.toLocaleString()}x${COLS.toLocaleString()} (${(originalCsv.length / 1024 / 1024).toFixed(2)} MB)`);

  const startEncode = performance.now();
  const hologram = encodeCsvHologram(originalCsv);
  const knotBytes = AmplituhedronKnot.toBytes(hologram.geometry);
  const encodeTime = performance.now() - startEncode;

  console.log(`[+] Structural Schema (Geometry) packed into: ${knotBytes.length} bytes`);
  console.log(`    - k (Columns): ${hologram.geometry.dimensionality}`);
  console.log(`    - n (Rows): ${hologram.geometry.staticVolume / hologram.geometry.dimensionality}`);
  console.log(`    - v (Total Cells): ${hologram.geometry.staticVolume}`);
  console.log(`[+] Raw Entropy Extracted (Dictionary length): ${hologram.ventDictionary.length.toLocaleString()} items`);
  console.log(`[+] Encoding Time: ${encodeTime.toFixed(2)}ms\n`);

  const startInflate = performance.now();
  const inflatedCsv = inflateCsvHologram(hologram, headers);
  const inflateTime = performance.now() - startInflate;

  if (inflatedCsv === originalCsv) {
    console.log(`[RESULT] SUCCESS: Matrix geometrically reconstructed in ${inflateTime.toFixed(2)}ms`);
  } else {
    console.log(`[RESULT] FAILURE: CSV distortion detected.`);
  }
}

runBenchmark();
